    "/api/system/users": {
      "get": {
        "summary": "查询用户列表（支持分页和排序）",
        "deprecated": false,
        "description": "<p>\n根据条件查询用户列表，支持分页、用户名筛选、真实姓名筛选、状态筛选和多字段排序。\n注意：内置账户（is_sys=1）会被过滤掉，不会出现在查询结果中。\n</p>",
