  "components": {
    "schemas": {
      "LoginResponse": {
        "type": "object",
        "properties": {
          "accessToken": {
            "type": "string",
            "description": "访问令牌\n<p>\nJWT格式的访问令牌，用于后续请求的身份验证\n</p>"
          }
        }
      },
      "ResultLoginResponse": {
        "type": "object",
        "properties": {
          "code": {
            "type": "integer",
            "description": "业务状态码"
          },
          "data": {
            "$ref": "#/components/schemas/LoginResponse",
            "description": "响应数据"
          },
          "error": {
            "type": "object",
            "properties": {},
            "description": "错误信息"
          },
          "message": {
            "type": "string",
            "description": "提示信息"
          }
        }
      },
      "LoginRequest": {
        "type": "object",
        "properties": {
          "username": {
            "type": "string",
            "description": "用户名\n<p>\n用户登录系统的用户名，用于身份验证\n</p>"
          },
          "password": {
            "type": "string",
            "description": "密码\n<p>\n用户登录密码，用于身份验证\n</p>"
          }
        },
        "required": [
          "username",
          "password"
        ]
      },
      "UserInfoVO": {
        "type": "object",
        "properties": {
          "userId": {
            "type": "string",
            "description": "用户ID\n<p>\n用户的唯一标识ID，由系统自动生成。\n</p>"
          },
          "avatar": {
            "type": "string",
            "description": "头像\n<p>\n用户头像的URL地址，可选字段。\n</p>"
          },
          "username": {
            "type": "string",
            "description": "用户名\n<p>\n用户的登录账号，用于系统认证。\n</p>"
          },
          "realName": {
            "type": "string",
            "description": "真实姓名\n<p>\n用户的真实姓名或显示名称。\n</p>"
          },
          "roleTitles": {
            "type": "array",
            "items": {
              "type": "string"
            },
            "description": "角色名称列表\n<p>\n用户拥有的角色名称集合，用于前端展示。\n</p>"
          },
          "roleIds": {
            "type": "array",
            "items": {
              "type": "string"
            },
            "description": "角色ID列表\n<p>\n用户拥有的角色ID集合，用于权限校验。\n</p>"
          },
          "desc": {
            "type": "string",
            "description": "描述\n<p>\n用户的备注或描述信息。\n</p>"
          },
          "email": {
            "type": "string",
            "description": "邮箱\n<p>\n用户的电子邮箱地址。\n</p>"
          },
          "homePath": {
            "type": "string",
            "description": "首页路径\n<p>\n用户登录后的默认跳转路径。\n</p>"
          },
          "deptTitles": {
            "type": "array",
            "items": {
              "type": "string"
            },
            "description": "部门名称列表\n<p>\n用户所属部门的名称集合，用于前端展示。\n</p>"
          },
          "deptIds": {
            "type": "array",
            "items": {
              "type": "string"
            },
            "description": "部门ID列表\n<p>\n用户所属部门的ID集合。\n</p>"
          },
          "status": {
            "type": "integer",
            "description": "状态\n<p>\n用户账号状态：0-禁用，1-启用。\n</p>"
          },
          "createDate": {
            "type": "string",
            "description": "创建时间\n<p>\n用户账号的创建时间。\n</p>"
          },
          "updateDate": {
            "type": "string",
            "description": "更新时间\n<p>\n用户信息的最后更新时间。\n</p>"
          }
        }
      },
      "ResultUserInfoVO": {
        "type": "object",
        "properties": {
          "code": {
            "type": "integer",
            "description": "业务状态码"
          },
          "data": {
            "$ref": "#/components/schemas/UserInfoVO",
            "description": "响应数据"
          },
          "error": {
            "type": "object",
            "properties": {},
            "description": "错误信息"
          },
          "message": {
            "type": "string",
            "description": "提示信息"
          }
        }
      },
      "MenuMetaVO": {
        "type": "object",
        "properties": {
          "activeIcon": {
            "type": "string",
            "description": "激活图标\n<p>\n菜单激活状态下显示的图标。\n</p>"
          },
          "activePath": {
            "type": "string",
            "description": "激活路径\n<p>\n菜单激活时的路由路径。\n</p>"
          },
          "affixTab": {
            "type": "boolean",
            "description": "是否固定在标签\n<p>\n菜单是否固定在标签栏：false-不固定，true-固定。\n</p>"
          },
          "affixTabOrder": {
            "type": "integer",
            "description": "固定标签页的排序\n<p>\n固定标签页在标签栏中的排序序号。\n</p>"
          },
          "badge": {
            "type": "string",
            "description": "徽章内容\n<p>\n菜单右上角的徽章显示内容。\n</p>"
          },
          "badgeType": {
            "type": "string",
            "description": "徽标类型\n<p>\n徽标的类型，如：dot（圆点）、normal（普通）等。\n</p>"
          },
          "badgeVariants": {
            "type": "string",
            "description": "徽标样式\n<p>\n徽标的样式变体，如：primary、success、warning、error等。\n</p>"
          },
          "hideChildrenInMenu": {
            "type": "boolean",
            "description": "是否隐藏子菜单\n<p>\n是否在菜单中隐藏子菜单：false-不隐藏，true-隐藏。\n</p>"
          },
          "hideInBreadcrumb": {
            "type": "boolean",
            "description": "是否在面包屑中隐藏\n<p>\n是否在面包屑导航中隐藏该菜单：false-不隐藏，true-隐藏。\n</p>"
          },
          "hideInMenu": {
            "type": "boolean",
            "description": "是否在菜单中隐藏\n<p>\n是否在菜单栏中隐藏该菜单：false-不隐藏，true-隐藏。\n</p>"
          },
          "hideInTab": {
            "type": "boolean",
            "description": "是否在标签栏中隐藏\n<p>\n是否在标签栏中隐藏该页面：false-不隐藏，true-隐藏。\n</p>"
          },
          "icon": {
            "type": "string",
            "description": "图标\n<p>\n菜单的图标标识，用于菜单栏显示。\n</p>"
          },
          "iframeSrc": {
            "type": "string",
            "description": "内嵌页面的iframe地址\n<p>\n如果菜单需要内嵌iframe页面，则填写iframe的src地址。\n</p>"
          },
          "keepAlive": {
            "type": "boolean",
            "description": "是否缓存标签页\n<p>\n访问该菜单后是否缓存页面状态：false-不缓存，true-缓存。\n</p>"
          },
          "link": {
            "type": "string",
            "description": "外链跳转路径\n<p>\n如果是外链菜单，则填写跳转的URL地址。\n</p>"
          },
          "maxNumOfOpenTab": {
            "type": "integer",
            "description": "标签页最大打开数量\n<p>\n同名标签页的最大打开数量限制，仅在打开同名标签页时生效。\n</p>"
          },
          "noBasicLayout": {
            "type": "boolean",
            "description": "无基础布局\n<p>\n该页面是否不使用基础布局框架：false-使用，true-不使用。\n</p>"
          },
          "openInNewWindow": {
            "type": "boolean",
            "description": "在新窗口打开页面\n<p>\n点击菜单是否在新窗口打开页面：false-当前窗口，true-新窗口。\n</p>"
          },
          "order": {
            "type": "integer",
            "description": "用于路由排序\n<p>\n菜单在路由中的排序权重，数值越小排序越靠前。\n</p>"
          },
          "query": {
            "type": "string",
            "description": "额外的路由参数\n<p>\n路由跳转时传递的额外查询参数，格式为 key=value&key=value。\n</p>"
          },
          "title": {
            "type": "string",
            "description": "标题\n<p>\n菜单的显示标题，用于标签栏和页面标题显示。\n</p>"
          },
          "domCached": {
            "type": "boolean",
            "description": "是否缓存DOM元素\n<p>\n配置当前路由是否要将route对应dom元素缓存起来：false-不缓存，true-缓存。\n</p>"
          },
          "menuVisibleWithForbidden": {
            "type": "boolean",
            "description": "菜单可见但访问被禁止\n<p>\n菜单可以看到，但是访问权限会被重定向到403页面：false-正常权限，true-禁止访问。\n</p>"
          }
        }
      },
      "MenuVO": {
        "type": "object",
        "properties": {
          "id": {
            "type": "string",
            "description": "菜单ID\n<p>\n菜单的唯一标识ID。\n</p>"
          },
          "pid": {
            "type": "string",
            "description": "父级菜单ID\n<p>\n父级菜单的唯一标识ID，用于构建菜单树形结构。顶级菜单为空字符串。\n</p>"
          },
          "type": {
            "type": "string",
            "description": "菜单类型\n<p>\n菜单类型标识，如：menu（菜单）、button（按钮）等。\n</p>"
          },
          "authCode": {
            "type": "string",
            "description": "权限标识\n<p>\n菜单的权限编码，用于前端权限控制和按钮级别的权限校验。\n</p>"
          },
          "name": {
            "type": "string",
            "description": "菜单名称\n<p>\n菜单的显示名称，用于前端菜单展示。\n</p>"
          },
          "path": {
            "type": "string",
            "description": "路由地址\n<p>\n菜单对应的路由路径或URL地址。\n</p>"
          },
          "component": {
            "type": "string",
            "description": "组件路径\n<p>\n前端组件的文件路径或组件名称，用于动态加载页面。\n</p>"
          },
